compliant:
// URL validation and allowlisting
[HttpGet("fetch")]
public async Task<string> FetchContent(string url)
{
    var allowedDomains = new[] { "api.example.com", "trusted-service.com" };
    var uri = new Uri(url);

    if (!allowedDomains.Contains(uri.Host.ToLower()) || 
        uri.Scheme != "https")
    {
        throw new ArgumentException("Invalid URL");
    }

    using var client = new HttpClient();
    return await client.GetStringAsync(url);
}

// Predefined endpoint mapping
public async Task<string> GetAllowedResource(string resourceId)
{
    var allowedUrls = new Dictionary<string, string>
    {
        ["user-data"] = "https://api.example.com/users",
        ["product-info"] = "https://catalog.example.com/products"
    };

    if (!allowedUrls.TryGetValue(resourceId, out var url))
    {
        throw new ArgumentException("Resource not found");
    }

    using var client = new HttpClient();
    return await client.GetStringAsync(url);
}

